prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?taskCount ?srcName ?tgtName WHERE {
  # Find the unique source and target tasks inside the specified model
  ?srcTask a bboExt:ChoreographyTask ;
           bbo:name ?srcName ;
           tai:belongsTo ?choreo .
  ?tgtTask a bboExt:ChoreographyTask ;
           bbo:name ?tgtName ;
           tai:belongsTo ?choreo .

  FILTER(?srcName = "Wybiera samochódo raz czas najmu")
  FILTER(?tgtName = "Przygotowuje nową umowe lub zostaje przy poprzedniej")

  ?model a bboExt:Model ;
         tai:normalizedId "4fba0078103d44d9846d4fbec51710cb" .
  ?choreo tai:belongsTo ?model .

  # Collect tasks reachable from source by following outgoing SequenceFlow paths until reaching the target.
  # We include any intermediate task (excluding source and target).
  {
    SELECT (COUNT(DISTINCT ?midTask) AS ?taskCount) WHERE {
      ?srcTask ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?midTask .
      ?midTask a bboExt:ChoreographyTask .
      FILTER(?midTask != ?srcTask)

      # Ensure the path can reach the target from the intermediate node
      ?midTask ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?tgtTask .
      FILTER(?midTask != ?tgtTask)
    }
  }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?name WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "4fba0078103d44d9846d4fbec51710cb" .
  ?choreo tai:belongsTo ?model .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("Wybiera samochódo")))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelIdProp ?modelIdValue ?task ?taskName WHERE {
  ?model a bboExt:Model .
  { ?model tai:normalizedId ?modelIdValue . BIND("normalizedId" AS ?modelIdProp) }
  UNION
  { ?model tai:originalId ?modelIdValue . BIND("originalId" AS ?modelIdProp) }
  FILTER(STR(?modelIdValue) = "4fba0078103d44d9846d4fbec51710cb")

  ?choreo tai:belongsTo ?model .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .
  FILTER(
    CONTAINS(LCASE(STR(?taskName)), LCASE("Wybiera")) ||
    CONTAINS(LCASE(STR(?taskName)), LCASE("Przygotowuje"))
  )
}
ORDER BY ?taskName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?reachable ?rName ?rType WHERE {
  BIND(IRI("https://www.teamingai-project.eu/kg/model/sid_55e03d8a_7ec7_4221_a353_afe03bfcd155") AS ?model)
  ?choreo tai:belongsTo ?model .

  ?srcTask a bboExt:ChoreographyTask ;
           tai:belongsTo ?choreo ;
           bbo:name "Wybiera samochód oraz czas najmu" .

  ?srcTask ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?reachable .
  OPTIONAL { ?reachable bbo:name ?rName . }
  OPTIONAL { ?reachable a ?rType . }
}
LIMIT 25
